head.script:
//-------------------------------------------------------------------------
// 전역변수
//-------------------------------------------------------------------------
scwin.empNo = $c.data.getMemInfo("userId");
scwin.loUpperLobranCd = $c.data.getMemInfo("loUpperLobranCd"); // 물류 상위 점소 코드
scwin.vCurDate = WebSquare.date.getCurrentServerDate();  // 서버를 기준으로 현재 날짜 반환
scwin.vQryStDt = scwin.vCurDate.substring(0, 6) + "01";  // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)

scwin.CREATE_AUTH   = "C" ;
scwin.RETRIEVE_AUTH = "R" ;
scwin.UPDATE_AUTH   = "U" ;
scwin.DELETE_AUTH   = "D" ;
scwin.PRINT_AUTH    = "P" ;
scwin.EXCEL_AUTH    = "X" ;
scwin.selectedRowIndex = 0;

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {
    const codeOptions = [
        { grpCd: "OP602", compID: "acb_transClsCd, gr_master:transClsCd" }, // 셀렉트
        // { grpCd: "OP608", compID: "lc_trffClsCd" }, // 셀렉트
    ];
    $c.data.setCommonCode(codeOptions);	

    const param= [
        {
            compID: "lc_trffClsCd",
            method: "getCodeList",
            param1: "OP608",
            param2: 1,
            param3: "S",

            // outputFields를 정의하면, 이게 자동으로 param4: [1, 3]으로 변환되어 서버로 전송됩니다.
            outputFields: ["CD", "CD_NM"]
        }
    ];
    $c.data.setDsCommonUtil(param);


    $c.gus.cfTurnCreateFlag(true);

    scwin.f_DisableObj();

};


//-------------------------------------------------------------------------
// 조회 / f_retrieve
//-------------------------------------------------------------------------
scwin.btn_retrieve_onClick = async function (e) {


    if (! await $c.gus.cfValidate(tb_searchCondition)){
        return;
    } 

    if(ed_cvsslMgntNo.getValue() =="" )
        {	
            $c.win.alert("조회 시 본선관리번호는 필수입니다.");	   
            return; 
        } 



    dma_condition.set("cvsslMgntNo", ed_cvsslMgntNo.getValue());
    dma_condition.set("clntNo_cond", ed_clntNo.getValue());
    dma_condition.set("vsslCnt", ed_vsslCnt.getValue());
    dma_condition.set("transClsCd", acb_transClsCd.getValue());
    dma_condition.set("blNo", ed_blNo.getValue());
    dma_condition.set("stConfirmDate", ica_stConfirmDate.getValue());
    dma_condition.set("edConfirmDate", ica_edConfirmDate.getValue());
    dma_condition.set("createYn", acb_createYn.getValue());

    $c.sbm.execute(sbm_condition)

};

//-------------------------------------------------------------------------
// 조회 완료시
//-------------------------------------------------------------------------
scwin.sbm_condition_submitDone = function (e) {
    try{
        if (e.responseJSON.resultDataSet[0].Code < 0)return; //onFail

        scwin.f_DisableObj();
        scwin.f_commonFieldClear();    
    } catch (e) {
       console.log("sbm_saveAcctRecvBdebt_submitdone : " + e);
    }


};


//-------------------------------------------------------------------------
// 컴포넌트 disable 처리
//-------------------------------------------------------------------------
setTimeout (scwin.f_DisableObj = function() {

    $c.gus.cfEnableObj(btn_save, false); 
    $c.gus.cfEnableObj(ed_bilgClntNo, false); 
    $c.gus.cfEnableObj(ed_bilgClntNm, false); 
    $c.gus.cfEnableObj(btn_bilgClntNo, false); 
    $c.gus.cfEnableObj(ed_selpchItemCd, false); 
    $c.gus.cfEnableObj(ed_selpchItemNm, false); 
    // $c.gus.cfEnableObj(btn_selpchItem, false); 
    $c.gus.cfEnableObj(ed_rmk, false); 
    $c.gus.cfEnableObj(ed_bilgLodeptCd, false); 
    $c.gus.cfEnableObj(ed_bilgLodeptNm, false); 
    // $c.gus.cfEnableObj(btn_bilgLodept, false); 
    $c.gus.cfEnableObj(lc_trffClsCd, false); 
    $c.gus.cfEnableObj(ica_rsltsStdDt, false); 
    $c.gus.cfEnableObj(lc_odrNo, false); 
    $c.gus.cfEnableObj(ed_sellLodeptCd, false); 
    $c.gus.cfEnableObj(ed_sellLodeptNm, false); 
    // $c.gus.cfEnableObj(btn_sellLodept, false); 

}, 100);


//-------------------------------------------------------------------------
// 조회조건 초기화
//-------------------------------------------------------------------------
scwin.btn_fieldClear_onClick = function (e) {
    ed_cvsslMgntNo.setValue("");
    ed_clntNo.setValue("");
    ed_clntNm.setValue("");
    ed_vsslCnt.setValue("");
    acb_transClsCd.setValue("");
    ed_blNo.setVAlue("");

};

//-------------------------------------------------------------------------
// 조회조건 초기화
//-------------------------------------------------------------------------
scwin.f_commonFieldClear = function() {

    ed_bilgClntNo.setValue("");
    ed_bilgClntNm.setValue("");

    ed_bilgLodeptCd.setValue("");
    ed_bilgLodeptNm.setValue("");

    ed_selpchItemCd.setValue("");
    ed_selpchItemNm.setValue("");

    lc_trffClsCd.setValue("");

    ed_sellLodeptCd.setValue("");
    ed_sellLodeptNm.setValue("");

    ed_rmk.setValue("");
    ica_rsltsStdDt.setValue("");
    lc_odrNo.setValue();

};



//-------------------------------------------------------------------------
// 그리드 본선관리번호 팝업
//-------------------------------------------------------------------------
scwin.btn_cvsslMgntNo_onClick = async function(e) {
    //팝업 화면에 데이터 보내는 방법 1. json형태로 팝업화면에서 getParameter로 받기
    let args = new Array();
    args [0] = ed_cvsslMgntNo.getValue();

    // 팝업 옵션 설정
    let options = {
        id: "taxPop", 
        type: "browserPopup",
        modal: "true",
        popupName: "본선관리번호검색팝업",
        width:  1100,                   
        height: 650
    };

    //상세화면 호출
    let rtn = await $c.win.openPopup("/ui/ds/op/wrkplan/stvwrkplan/op_204_01_07p.xml", options, args);       

    $c.gus.cfSetReturnValue(rtn, ed_cvsslMgntNo);

}


//-------------------------------------------------------------------------
// 화주 검색 팝업창 띄우기
//-------------------------------------------------------------------------
scwin.f_openClntPopUp = function(pAllSearch) {
    var inObj = ed_clntNo;
    var pairObj = ed_clntNm;

    if(!scwin.f_canOpenPopUp(inObj, pairObj)) {
        return;
    }

    //디테일 수입 대표거래처 팝업
    udc_clnt.cfCommonPopUp(
        scwin.udc_clnt_callBackFunc		// XML상의 SELECT ID	
        ,$c.gus.cfGetValue(inObj)		// 화면에서의 ??? Code Element의	Value
        ,$c.gus.cfGetValue(pairObj)	// 화면에서의 ??? Name Element의	Value
        ,"T"				// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
        ,null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
        ,null					// Title순서	
        ,null					// 보여주는 각 컬럼들의 폭	
        ,null					// 컬럼중에서 숨기는	컬럼 지정	
        ,null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
        ,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
        ,null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
        ,null					// 윈도우 위치 Y좌표	
        ,null					// 윈도우 위치 X좌표
        ,null					// 중복체크여부	("F")
        ,'F'				// 전체검색허용여부	("F")
        ,"대표거래처,거래처코드,거래처명"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
        );


}

scwin.f_canOpenPopUp = function(inObj, pairObj) {

        if($c.gus.cfIsNull(pairObj)) {
            if ($c.gus.cfGetValue(inObj) == "") {
                $c.gus.cfClearPairObj(inObj);
                $c.gus.cfSetHiddenValue(inObj,"");
                return false;
            }

            if ($c.gus.cfGetValue(inObj) == $c.gus.cfGetHiddenValue(inObj)) return false;

            return true;
        } 
    return true;
}

//-------------------------------------------------------------------------
// 팝업 버튼에 의한 팝업호출 여부 리턴 / DOM 직접 접근으로 사용 불가함
