//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function(inObj, pairObj, disGubun, isCode) {

    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업

    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, "", "T", "T");
    // inObj가 코드명 필드일 경우 팝업
    else
        scwin.f_openCommonPopUp(disGubun, "", pVal, "T", "T");


}

//-------------------------------------------------------------------------
// 팝업창 처리
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {

    // 선언부
    var rtnList = new Array();  // 공통POP-UP -> 요청화면 

    switch (disGubun) {
        case 1:
            // 청구처			
            udc_bilgClnt.cfCommonPopUp(
                scwin.udc_bilgClnt_callBackFunc
                , pCode.trim()
                , pName
                , pClose
                , "5"
                , null
                , null
                , null
                , null
                , null
                , null
                , null
                , null
                , null
                , pAllSearch
                , "청구처,청구처코드,청구처");

            break;

        case 2:
            // 청구부서 팝업			
            udc_bilgLodept.cfCommonPopUp(
                scwin.udc_bilgLodept_callBackFunc
                , pCode.trim()
                , pName
                , pClose
                , "2"
                , null
                , null
                , null
                , ",,,,,,,1"
                , null
                , null
                , null
                , null
                , null
                , null
                , "청구부서, 청구부서코드, 청구부서"
                );

            break;

        case 3:
            // 매출부서		
            udc_sellLodept.cfCommonPopUp(
                scwin.udc_sellLodept_callBackFunc
                , pCode.trim()
                , pName
                , pClose
                , "2"
                , null
                , null
                , null
                , ",,,,,,1,"
                , null
                , null
                , null
                , null
                , null
                , null
                , "매출부서,매출부서코드,매출부서");

            break;

        case 4:
            // 매출항목			
            udc_selpchItem.cfCommonPopUp(
                scwin.udc_selpchItem_callBackFunc// XML상의 SELECT ID	
                ,pCode					// 화면에서의 ??? Code Element의	Value
                ,pName					// 화면에서의 ??? Name Element의	Value
                ,pClose			// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                ,'5'					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                ,"항목코드,항목명"                 // Title순서	
                ,'150,210'			    // 보여주는 각 컬럼들의 폭	
                ,null		            // 컬럼중에서 숨기는	컬럼 지정	
                ,',,,,,'				    // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                ,'440'					// POP-UP뛰을때 원도우의	사용자 정의	폭
                ,'500'					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                ,null					// 윈도우 위치 Y좌표	
                ,null					// 윈도우 위치 X좌표
                ,null					// 중복체크여부	("F")
                ,'F'				    // 전체검색허용여부	("F")
                ,"매출입항목코드조회,항목코드,항목명"           // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")			  			
            );
            break;

        default:
            break;
    }
}




//-------------------------------------------------------------------------
// text상자팝업열기(코드(emedit)와 코드명(text) object가 있는경우
//-------------------------------------------------------------------------
scwin.f_openPopUpText = function(gubun, nmObj, cdObj, pWinCloseTF) {
	var pCode = "";
	var pName = "";
	var pSelectID = "";
	var pWtitleSearch = "";
	var rtnList = new Array();
	var pWhere = null;

	pCode = cdObj.value;
	pName = nmObj.value;

	if(gubun == 1){ //청구처
		pSelectID = "retrieveClntInfo";
		pWtitleSearch = "청구처,청구처코드,청구처";
		pDispCnt = "5";
		pTitle = null;
	}else if(gubun == 3){ //매출부서	
		pSelectID = "retrieveLogisDeptInfo";
		pWtitleSearch = "매출부서,매출부서코드,매출부서";
		pTitle = null;
		pDispCnt = "2";
		pWhere = ",,,,,,1,";
	}else if(gubun == 5){ //청구부서	
		pSelectID = "retrieveLogisDeptInfo";
		pWtitleSearch = "청구부서,청구부서코드,청구부서";
		pTitle = null;
		pDispCnt = "2";
		pWhere = ",,,,,,,1";
	}

	rtnList = cfCommonPopUp(pSelectID,						//pSelectID
							pCode,							//pCode
							pName,							//pName
							pWinCloseTF,					//pWinCloseTF
							pDispCnt,						//pDispCnt
							pTitle,							//pTitle
							null,							//pWidth
							null,							//pHidden
							pWhere,							//pWhere
							null,							//pW
							null,							//pH
							null,							//pTop
							null,							//pLeft
							null,							//pExistTF - 중복체크여부	("F")
							null,							//pAllSearchTF - 전체검색허용여부	("F")
							pWtitleSearch);					//pWtitleSearch - POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")

	if ( rtnList != null) {
		if(rtnList[0] == "N/A"){ //팝업에서 닫기버튼 클릭시	
			cfSetReturnValue(rtnList, cdObj, nmObj);			
		}else{
			cdObj.value = rtnList[0];
			nmObj.value = rtnList[1];

			cdObj.hidVal = rtnList[0];
			nmObj.hidVal = rtnList[1];


		}
	}else{
		cfInitObjects([cdObj, nmObj]);
		cfInitHidVal([cdObj, nmObj]);		
	}    


};

// scwin.f_openPopUpTextBefore = function() {

// };

