scwin.sbm_odrNo_submitDone = function (e) {
    try{
        if (e.responseJSON.resultDataSet[0].Code < 0)return; //onFail
        lc_odrNo.setValue(ds_odrNo.getCellData(0, "odrNo"));
    } catch (e) {
       console.log("sbm_saveAcctRecvBdebt_submitdone : " + e);
    }


};

scwin.sbm_master_submitDone = function (e) {

    try{
        if (e.responseJSON.resultDataSet[0].Code < 0)return; //onFail
        $c.win.alert(MSG_CM_INF_001);
        scwin.btn_retrieve_onClick()
        scwin.f_commonFieldClear();
    } catch (e) {
       console.log("sbm_saveAcctRecvBdebt_submitdone : " + e);
    }

};

