// 엑셀 다운로드
//-------------------------------------------------------------------------
scwin.runExcel = async function() {
    let options = {
        fileName : "코일현황.xlsx",
        sheetName : "코일현황",
        removeColumns : 0
    }

    let grdObj = gr_master;

    let infoArr = {};

    if(ds_master.getTotalRow() == 0) {
        $c.win.alert(MSG_CM_WRN_002);
    } else {
        if(await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?")) {
            $c.data.downloadGridViewExcel(grdObj, options, infoArr)
        }
    }

}

scwin.udc_ConfirmDate_onBlurFrom = async function (e) {
    let dateStr = ica_stConfirmDate.getValue()

    // 종료일자 체크
    if (await ica_stConfirmDate.getValue() > ica_edConfirmDate.getValue() && ica_edConfirmDate.getValue().length == 8 ){
        $c.win.alert("시작일자가 종료일자 이전이여야 합니다.") 
            ica_stConfirmDate.setValue("");
            ica_stConfirmDate.focus();
            return;
    } else {
        let minY = 1900;
        let maxY = 2099;
        let strY = dateStr.substring(0,4);

        // 형식 체크
    if((! await $c.date.isDate(dateStr) && dateStr.length == 8) || parseInt(strY) < minY || parseInt(strY) > maxY ) {
        $c.win.alert("날짜 형식이 올바르지 않습니다.", function() {
            ica_stConfirmDate.setValue("");
            ica_stConfirmDate.focus();
            return;
            });
        }
    };
};

scwin.udc_ConfirmDate_onBlurTo = async function (e) {
    let dateStr = ica_edConfirmDate.getValue()

    // 종료일자 체크
    if (await ica_stConfirmDate.getValue() > ica_edConfirmDate.getValue() && ica_edConfirmDate.getValue().length == 8 ){
        $c.win.alert("종료일자는 시작일자보다 이후여야 합니다.") 
            ica_edConfirmDate.setValue("");
            ica_edConfirmDate.focus();
            return;
    } else {
        let minY = 1900;
        let maxY = 2099;
        let strY = dateStr.substring(0,4);

        // 형식 체크
    if((! await $c.date.isDate(dateStr) && dateStr.length == 8) || parseInt(strY) < minY || parseInt(strY) > maxY ) {
        $c.win.alert("날짜 형식이 올바르지 않습니다.", function() {
            ica_edConfirmDate.setValue("");
            ica_edConfirmDate.focus();
            return;
            });
        }
    };
};

